solution_code:
#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        std::string token;
        std::cin >> token;
        if (token == "STATIC") {
            std::cout << "static library\n";
        } else if (token == "DYNAMIC") {
            std::cout << "dynamic library\n";
        } else {
            std::cout << "other\n";
        }
    }
    return 0;
}

