#include <iostream>
#include <string>

int main() {
    int n;
    std::cin >> n;
    long long total = 0;
    for (int i = 0; i < n; ++i) {
        long long size;
        std::string status;
        std::cin >> size >> status;
        // Bug: sums unused files instead of used files
        if (status == "unused") {
            total += size;
        }
    }
    std::cout << "Total: " << total << " bytes\n";
    return 0;
}

